import{_ as e,o as a,c as d,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Random Image API và Public Gallery","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/Other/random-image-api-and-public-gallery.md","filePath":"vi-VN/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),r={name:"vi-VN/Other/random-image-api-and-public-gallery.md"};function o(c,t,s,l,n,h){return a(),d("div",null,[...t[0]||(t[0]=[i(`<h1 id="random-image-api-va-public-gallery" tabindex="-1">Random Image API và Public Gallery <a class="header-anchor" href="#random-image-api-va-public-gallery" aria-label="Permalink to &quot;Random Image API và Public Gallery&quot;">​</a></h1><p>Cả hai features được cấu hình tại:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>Random Image API trả về một random file từ selected directories. Hữu ích cho site backgrounds, avatar rotation hoặc random image calls từ external pages.</p><p>Sau khi bật, dùng:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="random-image-api-settings" tabindex="-1">Random Image API Settings <a class="header-anchor" href="#random-image-api-settings" aria-label="Permalink to &quot;Random Image API Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td>Bật hoặc tắt endpoint <code>/random</code>. Khi disabled, access bị forbidden.</td></tr><tr><td>Directories</td><td>Giới hạn directories mà random API được dùng. Directories không nằm ở đây sẽ không được API dùng.</td></tr><tr><td>Call demo</td><td>Generate random API links để bạn copy trực tiếp.</td></tr></tbody></table><p>Bạn có thể chọn nhiều directories. Ví dụ, nếu chỉ allow <code>/landscape/</code> và <code>/portrait/</code>, random API chỉ chọn files từ các directories đó và subdirectories của chúng.</p><h2 id="random-image-api-parameters" tabindex="-1">Random Image API Parameters <a class="header-anchor" href="#random-image-api-parameters" aria-label="Permalink to &quot;Random Image API Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Example</th><th>Purpose</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>Chỉ định random directory.</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>Chỉ định media type. Dùng <code>image</code>, <code>video</code>, <code>audio</code> hoặc comma-separated combinations.</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>Filter image orientation. Dùng <code>portrait</code>, <code>landscape</code> hoặc <code>auto</code>.</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Return format. Để trống nghĩa là redirect, <code>url</code> trả plain text URL, <code>json</code> trả JSON.</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>Dùng với <code>type=url</code> để trả full URL.</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Filter theo age rating.</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>Chỉ trả files chứa các tags này.</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>Exclude files chứa các tags này.</td></tr></tbody></table><h2 id="return-formats" tabindex="-1">Return Formats <a class="header-anchor" href="#return-formats" aria-label="Permalink to &quot;Return Formats&quot;">​</a></h2><p>Không có <code>type</code>, API redirect trực tiếp tới random file URL.</p><p>Với <code>type=url</code>, API trả text URL.</p><p>Với <code>type=json</code>, API trả file information, gồm file URL, file ID, file name, file type, tags, rating và metadata liên quan.</p><h2 id="access-rules" tabindex="-1">Access Rules <a class="header-anchor" href="#access-rules" aria-label="Permalink to &quot;Access Rules&quot;">​</a></h2><p>Random Image API tuân theo public access rules:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Directory restriction</td><td>Chỉ files trong allowed directories mới được chọn.</td></tr><tr><td>Blocklist</td><td>Blocklisted files bị loại khỏi random pool.</td></tr><tr><td>Allowlist mode</td><td>Khi enabled, chỉ files allowed cho public access được return.</td></tr><tr><td>Age rating</td><td>R12, R16, R18 và content tương tự được filter theo current access mode.</td></tr></tbody></table><p>Nếu sau filtering không có file match, API trả no matching result.</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>Random Image API cache directory candidate pools để tăng speed.</p><p>Sau khi files thay đổi, ImgBed update directory cache version, và requests sau đó rebuild candidate pool. Empty directories được cache ngắn để tránh repeated queries.</p><h2 id="public-gallery" tabindex="-1">Public Gallery <a class="header-anchor" href="#public-gallery" aria-label="Permalink to &quot;Public Gallery&quot;">​</a></h2><p>Public gallery cung cấp read-only public browsing page cho directories bạn cho phép visitors xem.</p><p>Sau khi bật, visitors có thể mở:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="public-gallery-settings" tabindex="-1">Public Gallery Settings <a class="header-anchor" href="#public-gallery-settings" aria-label="Permalink to &quot;Public Gallery Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td>Bật hoặc tắt public gallery. Khi disabled, visitors không thể browse.</td></tr><tr><td>Image loading mode</td><td>Kiểm soát previews dùng original images hay thumbnails.</td></tr><tr><td>Open directories</td><td>Đặt directories visitors được access.</td></tr></tbody></table><h2 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Purpose</th></tr></thead><tbody><tr><td>Original</td><td>Visitor page load original files trực tiếp.</td></tr><tr><td>Thumbnail</td><td>Visitor page ưu tiên thumbnails để tải nhanh hơn.</td></tr></tbody></table><h2 id="open-directories" tabindex="-1">Open Directories <a class="header-anchor" href="#open-directories" aria-label="Permalink to &quot;Open Directories&quot;">​</a></h2><p>Open directories quyết định visitors thấy được gì.</p><p>Ví dụ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Visitors sau đó có thể access:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Subdirectories cũng có thể được mở, ví dụ <code>/2026/lucky/</code>. Visitors bị block khỏi directories không được open.</p><h2 id="public-gallery-features" tabindex="-1">Public Gallery Features <a class="header-anchor" href="#public-gallery-features" aria-label="Permalink to &quot;Public Gallery Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Browse directories</td><td>Xem files và subdirectories trong open directories.</td></tr><tr><td>Search</td><td>Search theo file name, file ID hoặc tags.</td></tr><tr><td>Type filter</td><td>Filter images, videos, audio hoặc other files.</td></tr><tr><td>Tag filter</td><td>Include hoặc exclude selected tags.</td></tr><tr><td>Orientation filter</td><td>Filter landscape hoặc portrait images.</td></tr><tr><td>Time filter</td><td>Filter theo upload time range.</td></tr><tr><td>Extension filter</td><td>Filter theo file extension.</td></tr><tr><td>Copy link</td><td>Copy file access links.</td></tr><tr><td>Media preview</td><td>Xem hoặc phát images, videos và audio trên visitor page.</td></tr></tbody></table><h2 id="public-gallery-access-rules" tabindex="-1">Public Gallery Access Rules <a class="header-anchor" href="#public-gallery-access-rules" aria-label="Permalink to &quot;Public Gallery Access Rules&quot;">​</a></h2><p>Public gallery cũng tuân theo public access rules:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Open directories</td><td>Chỉ allowed directories được hiển thị.</td></tr><tr><td>Access mode</td><td>Content được filter theo current age-rating access mode.</td></tr><tr><td>Allowlist mode</td><td>Khi enabled, chỉ files allowed cho public access được hiển thị.</td></tr><tr><td>Blocklist</td><td>Blocklisted files bị ẩn.</td></tr></tbody></table>`,43)])])}const m=e(r,[["render",o]]);export{u as __pageData,m as default};
